class TextEditor:
    def __init__(self):
        self.text = ''
        self.pos = 0  # cursor position in text
    def addText(self, text):
        self.text = self.text[:self.pos] + text + self.text[self.pos:]
        self.pos += len(text)
    def deleteText(self, k):
        actual = min(k, self.pos)
        self.text = self.text[:self.pos - actual] + self.text[self.pos:]
        self.pos -= actual
        return actual
    def cursorLeft(self, k):
        self.pos = max(0, self.pos - k)
        start = max(0, self.pos - 10)
        return self.text[start:self.pos]
    def cursorRight(self, k):
        self.pos = min(len(self.text), self.pos + k)
        start = max(0, self.pos - 10)
        return self.text[start:self.pos]

