class TextEditor:
    def __init__(self):
        self.left = []   # chars before cursor, top = adjacent to cursor
        self.right = []  # chars after cursor, top = adjacent to cursor

    def addText(self, text: str) -> None:
        for c in text:
            self.left.append(c)

    def deleteText(self, k: int) -> int:
        actual = min(k, len(self.left))
        for _ in range(actual):
            self.left.pop()
        return actual

    def _left_str(self):
        n = min(10, len(self.left))
        return ''.join(self.left[-n:]) if n else ''

    def cursorLeft(self, k: int) -> str:
        for _ in range(min(k, len(self.left))):
            self.right.append(self.left.pop())
        return self._left_str()

    def cursorRight(self, k: int) -> str:
        for _ in range(min(k, len(self.right))):
            self.left.append(self.right.pop())
        return self._left_str()

