class TextEditor {
    constructor() {
        this.left = [];   // chars before cursor
        this.right = [];  // chars after cursor (reversed)
    }
    addText(text) {
        for (const c of text) this.left.push(c);
    }
    deleteText(k) {
        const actual = Math.min(k, this.left.length);
        for (let i = 0; i < actual; i++) this.left.pop();
        return actual;
    }
    _leftStr() {
        const n = Math.min(10, this.left.length);
        return this.left.slice(this.left.length - n).join('');
    }
    cursorLeft(k) {
        const moves = Math.min(k, this.left.length);
        for (let i = 0; i < moves; i++) this.right.push(this.left.pop());
        return this._leftStr();
    }
    cursorRight(k) {
        const moves = Math.min(k, this.right.length);
        for (let i = 0; i < moves; i++) this.left.push(this.right.pop());
        return this._leftStr();
    }
}
